The correct way to integrate would be to use `router.events`, as well as making sure you don't send a Next router.push due to an InstantSearch navigation, this can be done as follows: https://codesandbox.io/s/infallible-fog-ehsvqo?file=/pages/index.js

```js
const pathToSearchState = (path) =>
  path.includes("?") ? qs.parse(path.substring(path.indexOf("?") + 1)) : {};

const createURL = (state) => `?${qs.stringify(state)}`;

export default function IndexPage() {
  const searchClient = algoliasearch(
    "latency",
    "6be0576ff61c053d5f9a3225e2a90f76"
  );
  const router = useRouter();
  const [searchState, setSearchState] = useState(
    pathToSearchState(router.asPath)
  );
  const debouncedSetState = useRef();

  useEffect(() => {
    const listener = () => {
      setSearchState(pathToSearchState(router.asPath));
    };

    router.events.on("routeChangeComplete", listener);

    return () => router.events.off("routeChangeComplete", listener);
  }, [router]);

  return (
      <InstantSearch
        searchState={searchState}
        searchClient={searchClient}
        indexName="instant_search"
        onSearchStateChange={(nextSearchState) => {
          clearTimeout(debouncedSetState.current);

          debouncedSetState.current = setTimeout(() => {
            const href = createURL(nextSearchState);

            window.history.pushState(
              window.history.state,
              document.title,
              href
            );
          }, 400);

          setSearchState(nextSearchState);
        }}
      >
 // ...
```

the debouncing of updating the URL isn't required, but recommended, as browsers tend to get slow if the query string is updated often.

Hope that helps!
